private void sendPing(Socket socket, boolean closeAfterSend) throws IOException {
        socket.getOutputStream().write(1);
        socket.getOutputStream().flush();
        if (closeAfterSend) {
            socket.close();
        } else {
            System.out.println("socket left open intentionally");
        }
    }

